import React, { useEffect, useState } from 'react';
import { View, Button, Text } from 'react-native';
import { authorize, refresh } from 'react-native-app-auth';

const config = {
  issuer: 'https://your-oauth-server.com',
  clientId: 'your_client_id',
  redirectUrl: 'yourapp://callback',
  scopes: ['openid', 'profile', 'email'],
  serviceConfiguration: {
    authorizationEndpoint: 'https://your-oauth-server.com/auth',
    tokenEndpoint: 'https://your-oauth-server.com/token',
  },
};

const App = () => {
  const [accessToken, setAccessToken] = useState(null);
  const [refreshToken, setRefreshToken] = useState(null);

  const authenticate = async () => {
    try {
      const result = await authorize(config);
      setAccessToken(result.accessToken);
      setRefreshToken(result.refreshToken);
    } catch (error) {
      console.error('Authentication Error:', error);
    }
  };

  const refreshAccessToken = async () => {
    if (refreshToken) {
      try {
        const newToken = await refresh(config, {
          refreshToken: refreshToken,
        });
        setAccessToken(newToken.accessToken);
        setRefreshToken(newToken.refreshToken);
      } catch (error) {
        console.error('Token Refresh Error:', error);
      }
    }
  };

  useEffect(() => {
    const interval = setInterval(() => {
      refreshAccessToken();
    }, 600000); // Refresh token every 10 minutes

    return () => clearInterval(interval);
  }, [refreshToken]);

  return (
    <View>
      <Button title="Authenticate" onPress={authenticate} />
      {accessToken && <Text>Access Token: {accessToken}</Text>}
    </View>
  );
};

export default App;